 private static function path(){return dirname(__DIR__).'/contracts/bioprocess-monitoring-control-v0222.json';} public static function contract(){if(!is_file(self::path()))throw new RuntimeException('Monitoring contract missing.');$d=json_decode(file_get_contents(self::path()),true);if(!is_array($d))throw new RuntimeException('Monitoring contract invalid.');return $d;}
 private static function finite($v,$l){if(!is_numeric($v))throw new InvalidArgumentException($l.' must be numerical.');$n=(float)$v;if(!is_finite($n))throw new InvalidArgumentException($l.' must be finite.');return $n;} private static function mean($v){return array_sum($v)/count($v);} private static function sd($v){if(count($v)<2)return 0.0;$m=self::mean($v);$s=0.0;foreach($v as $x)$s+=pow($x-$m,2);return sqrt($s/(count($v)-1));}
