 public static function analyze($rows,$id,$o=array()){$c=self::channel($id);if(!is_array($rows)||!$rows)throw new InvalidArgumentException('Monitoring analysis requires data rows.');$window=max(2,(int)self::finite($o['rollingWindow']??self::contract()['defaults']['rollingWindow'],'rollingWindow'));$low=self::finite($o['low']??$c['low'],'low');$high=self::finite($o['high']??$c['high'],'high');$rate=self::finite($o['rateLimit']??$c['rateLimit'],'rateLimit');$cvlim=self::finite($o['cvLimit']??$c['cvLimit'],'cvLimit');$points=array();$missing=0;foreach($rows as $i=>$r){$raw=$r[$id]??null;if($raw===''||$raw===null){$missing++;continue;}$points[]=array('time'=>self::finite($r['time']??null,'time on row '.($i+1)),'value'=>self::finite($raw,$id.' on row '.($i+1)),'phase'=>(string)($r['phase']??''),'run'=>(string)($r['run']??'run-1'));}if(!$points)throw new InvalidArgumentException('No numerical '.$id.' values were found.');usort($points,static function($a,$b){return $a['time']<=>$b['time'];});$values=array_column($points,'value');$flags=array();foreach($points as $i=>&$p){$slice=array_slice($values,max(0,$i-$window+1),$window);$m=self::mean($slice);$s=self::sd($slice);$cv=$m==0.0?null:abs($s/$m)*100.0;$p['rollingMean']=$m;$p['rollingSd']=$s;$p['rollingCvPercent']=$cv;if($p['value']<$low)$flags[]=array('type'=>'low-limit','severity'=>'action','time'=>$p['time'],'value'=>$p['value'],'limit'=>$low);if($p['value']>$high)$flags[]=array('type'=>'high-limit','severity'=>'action','time'=>$p['time'],'value'=>$p['value'],'limit'=>$high);if($i>0){$dt=$p['time']-$points[$i-1]['time'];if($dt<=0)$flags[]=array('type'=>'time-order','severity'=>'action','time'=>$p['time']);else{$r=abs(($p['value']-$points[$i-1]['value'])/$dt);if($r>$rate)$flags[]=array('type'=>'rate-of-change','severity'=>'warning','time'=>$p['time'],'value'=>$r,'limit'=>$rate);}}if($cv!==null&&$cv>$cvlim)$flags[]=array('type'=>'rolling-cv','severity'=>'warning','time'=>$p['time'],'value'=>$cv,'limit'=>$cvlim);}unset($p);$auc=0.0;for($i=1;$i<count($points);$i++)$auc+=($points[$i]['time']-$points[$i-1]['time'])*($points[$i]['value']+$points[$i-1]['value'])/2.0;$missingpct=$missing/count($rows)*100.0;$action=count(array_filter($flags,static function($f){return $f['severity']==='action';}));$warning=count(array_filter($flags,static function($f){return $f['severity']==='warning';}));$m=self::mean($values);$s=self::sd($values);return array('schema'=>'sc-lab-bioprocess-monitoring-analysis/1.0','version'=>self::VERSION,'channel'=>$c,'limits'=>array('low'=>$low,'high'=>$high,'rateLimit'=>$rate,'cvLimit'=>$cvlim,'rollingWindow'=>$window),'summary'=>array('rowCount'=>count($rows),'validPointCount'=>count($points),'missingCount'=>$missing,'missingPercent'=>$missingpct,'mean'=>$m,'standardDeviation'=>$s,'coefficientOfVariationPercent'=>$m==0.0?null:abs($s/$m)*100.0,'minimum'=>min($values),'maximum'=>max($values),'initial'=>$values[0],'final'=>$values[count($values)-1],'areaUnderCurve'=>$auc,'actionCount'=>$action,'warningCount'=>$warning,'status'=>$action?'action':($warning?'warning':'normal')),'points'=>$points,'flags'=>$flags);}
 public static function pid($p=array()){$sp=self::finite($p['setpoint']??40,'setpoint');$pv=self::finite($p['pv0']??20,'pv0');$kp=self::finite($p['kp']??1,'kp');$ki=self::finite($p['ki']??.2,'ki');$kd=self::finite($p['kd']??.05,'kd');$gain=self::finite($p['processGain']??1,'processGain');$tau=max(1.0e-9,self::finite($p['timeConstant']??3,'timeConstant'));$dt=max(1.0e-6,self::finite($p['dt']??.1,'dt'));$duration=max($dt,self::finite($p['duration']??20,'duration'));$umin=self::finite($p['outputMin']??0,'outputMin');$umax=self::finite($p['outputMax']??100,'outputMax');$integral=0.0;$prev=$sp-$pv;$points=array();for($t=0.0;$t<=$duration+1.0e-9;$t+=$dt){$err=$sp-$pv;$integral+=$err*$dt;$der=($err-$prev)/$dt;$out=min($umax,max($umin,$kp*$err+$ki*$integral+$kd*$der));$pv+=$dt*(($gain*$out-$pv)/$tau);$points[]=array('time'=>$t,'setpoint'=>$sp,'processValue'=>$pv,'controllerOutput'=>$out,'error'=>$err);$prev=$err;}return array('schema'=>'sc-lab-bioprocess-control-simulation/1.0','version'=>self::VERSION,'points'=>$points,'summary'=>array('finalProcessValue'=>$points[count($points)-1]['processValue'],'finalError'=>$points[count($points)-1]['error']));}
 public static function compare($rows,$id){$channel=self::channel($id);$groups=array();foreach($rows as $i=>$row){$raw=$row[$id]??null;if($raw===''||$raw===null)continue;$run=(string)($row['run']??'run-1');if(!isset($groups[$run]))$groups[$run]=array();$groups[$run][]=array('time'=>self::finite($row['time']??null,'time on row '.($i+1)),'value'=>self::finite($raw,$id.' on row '.($i+1)));}if(!$groups)throw new InvalidArgumentException('No comparable run data were found.');$runs=array();$finals=array();foreach($groups as $name=>$points){usort($points,static function($a,$b){return $a['time']<=>$b['time'];});$values=array_column($points,'value');$auc=0.0;for($i=1;$i<count($points);$i++)$auc+=($points[$i]['time']-$points[$i-1]['time'])*($points[$i]['value']+$points[$i-1]['value'])/2.0;$final=$values[count($values)-1];$finals[]=$final;$runs[]=array('run'=>$name,'pointCount'=>count($points),'mean'=>self::mean($values),'standardDeviation'=>self::sd($values),'minimum'=>min($values),'maximum'=>max($values),'initial'=>$values[0],'final'=>$final,'areaUnderCurve'=>$auc,'points'=>$points);}return array('schema'=>'sc-lab-bioprocess-run-comparison/1.0','version'=>self::VERSION,'channel'=>$channel,'runs'=>$runs,'summary'=>array('runCount'=>count($runs),'finalMean'=>self::mean($finals),'finalStandardDeviation'=>self::sd($finals),'finalRange'=>max($finals)-min($finals)));}
